import requests

GROUP_ID = "<group-object-id>"
USER_ID  = "<user-object-id>"
BASE     = "https://graph.microsoft.com/v1.0"
HDR      = {"Authorization": f"Bearer {access_token}", "Content-Type": "application/json"}

# Add a single member
requests.post(
    f"{BASE}/groups/{GROUP_ID}/members/$ref",
    headers=HDR,
    json={"@odata.id": f"{BASE}/directoryObjects/{USER_ID}"}
)

# Add multiple members in one call (up to 20 per request)
MEMBER_IDS = ["<user-id-1>", "<user-id-2>", "<sp-id-3>"]
requests.patch(
    f"{BASE}/groups/{GROUP_ID}",
    headers=HDR,
    json={
        "members@odata.bind": [f"{BASE}/directoryObjects/{mid}" for mid in MEMBER_IDS]
    }
)

# Remove a member
requests.delete(
    f"{BASE}/groups/{GROUP_ID}/members/{USER_ID}/$ref",
    headers={"Authorization": f"Bearer {access_token}"}
)

# List current members (paginated)
url = f"{BASE}/groups/{GROUP_ID}/members"
params = {"$select": "displayName,userPrincipalName,id", "$top": 999}
members = []
while url:
    r = requests.get(url, headers={"Authorization": f"Bearer {access_token}"}, params=params)
    data = r.json()
    members.extend(data.get("value", []))
    url = data.get("@odata.nextLink")
    params = {}
print(f"{len(members)} members in group")

import requests
from concurrent.futures import ThreadPoolExecutor

def get_member_count(token: str, group_id: str) -> int:
    r = requests.get(
        f"https://graph.microsoft.com/v1.0/groups/{group_id}/members/$count",
        headers={"Authorization": f"Bearer {token}", "ConsistencyLevel": "eventual"}
    )
    return int(r.text) if r.ok else -1

def get_owner_count(token: str, group_id: str) -> int:
    r = requests.get(
        f"https://graph.microsoft.com/v1.0/groups/{group_id}/owners/$count",
        headers={"Authorization": f"Bearer {token}", "ConsistencyLevel": "eventual"}
    )
    return int(r.text) if r.ok else -1

# Fetch all security groups
url = "https://graph.microsoft.com/v1.0/groups"
params = {"$filter": "securityEnabled eq true", "$select": "id,displayName,createdDateTime", "$top": 999}
groups = []
while url:
    r = requests.get(url, headers={"Authorization": f"Bearer {access_token}"}, params=params)
    data = r.json()
    groups.extend(data.get("value", []))
    url = data.get("@odata.nextLink"); params = {}

print(f"Auditing {len(groups)} security groups...")
issues = []
for g in groups:
    members = get_member_count(access_token, g["id"])
    owners  = get_owner_count(access_token, g["id"])
    if members == 0 or owners == 0:
        issues.append({
            "name": g["displayName"],
            "created": g["createdDateTime"][:10],
            "members": members,
            "owners": owners
        })

print(f"\n{len(issues)} groups with issues:")
for i in sorted(issues, key=lambda x: x["members"]):
    print(f"  {i['name']:<40} members={i['members']:>3}  owners={i['owners']:>2}  created={i['created']}")

import requests

def find_license_conflicts(token: str, group_id: str) -> list:
    r = requests.get(
        f"https://graph.microsoft.com/v1.0/groups/{group_id}/membersWithLicenseErrors",
        headers={"Authorization": f"Bearer {token}"},
        params={"$select": "userPrincipalName,id,licenseAssignmentStates"}
    )
    users = r.json().get("value", [])
    results = []
    for u in users:
        for state in u.get("licenseAssignmentStates", []):
            if state.get("state") == "Error":
                results.append({
                    "upn": u["userPrincipalName"],
                    "sku": state.get("skuId"),
                    "error": state.get("error")
                })
    return results

conflicts = find_license_conflicts(access_token, GROUP_ID)
for c in conflicts:
    print(f"{c['upn']:<40}  Error: {c['error']}")
