import requests
from typing import Set

BASE = "https://graph.microsoft.com/v1.0"
HDR  = {"Authorization": f"Bearer {access_token}", "Content-Type": "application/json"}

def get_current_members(group_id: str) -> Set[str]:
    url = f"{BASE}/groups/{group_id}/members"
    params = {"$select": "id", "$top": 999}
    ids = set()
    while url:
        r = requests.get(url, headers=HDR, params=params)
        data = r.json()
        ids.update(m["id"] for m in data.get("value", []))
        url = data.get("@odata.nextLink"); params = {}
    return ids

def add_members(group_id: str, user_ids: Set[str]) -> None:
    ids = list(user_ids)
    for i in range(0, len(ids), 20):  # Graph allows 20 per PATCH
        batch = ids[i:i + 20]
        requests.patch(
            f"{BASE}/groups/{group_id}", headers=HDR,
            json={"members@odata.bind": [f"{BASE}/directoryObjects/{uid}" for uid in batch]}
        )

def remove_members(group_id: str, user_ids: Set[str]) -> None:
    for uid in user_ids:
        requests.delete(f"{BASE}/groups/{group_id}/members/{uid}/$ref", headers=HDR)

def sync_group(group_id: str, desired: Set[str]) -> None:
    current   = get_current_members(group_id)
    to_add    = desired - current
    to_remove = current - desired
    print(f"  +{len(to_add)} / -{len(to_remove)} members")
    if to_add:    add_members(group_id, to_add)
    if to_remove: remove_members(group_id, to_remove)

# Desired membership sourced from an external HR system
hr_employee_ids = {"aaaa1111-...", "bbbb2222-...", "cccc3333-..."}
sync_group("<security-group-id>", hr_employee_ids)
